async function main() {
  console.log('Seeding Teknoloji & Yazılım brands...\n');

  const allCats = await prisma.category.findMany();
  const categoryMap = new Map<string, string>();
  for (const c of allCats) categoryMap.set(c.slug, c.id);

  let totalBrands = 0, totalSources = 0, totalErrors = 0;

  for (const { market, brands } of MARKET_BRANDS) {
    console.log(`\n── ${market} (${brands.length} brands) ──`);
    let brandsOk = 0, sourcesCreated = 0, errors = 0;

    for (const entry of brands) {
      const slug = toSlug(entry.name);
      const categoryId = categoryMap.get(entry.categorySlug) ?? null;
      if (!categoryId) { console.warn(`  Category not found: ${entry.categorySlug}`); errors++; continue; }

      try {
        const brand = await prisma.brand.upsert({
          where: { slug_market: { slug, market } },
          update: { name: entry.name, websiteUrl: entry.websiteUrl, categoryId },
          create: { name: entry.name, slug, websiteUrl: entry.websiteUrl, market, categoryId },
        });

        const existingSource = await prisma.crawlSource.findFirst({
          where: { brandId: brand.id, crawlMethod: 'HTML' },
        });

        if (!existingSource) {
          await prisma.crawlSource.create({
            data: {
              brandId: brand.id,
              name: `${entry.name} Deals`,
              crawlMethod: 'HTML',
              seedUrls: entry.seedUrls,
              maxDepth: 2,
              schedule: '0 4 * * *',
              agingDays: 7,
              market,
              isActive: true,
            },
          });
          sourcesCreated++;
        }
        brandsOk++;
      } catch (err) {
        console.error(`  ERROR: ${entry.name} — ${(err as Error).message}`);
        errors++;
      }
    }

    console.log(`  ${brandsOk} brands ok, ${sourcesCreated} new sources, ${errors} errors`);
    totalBrands += brandsOk; totalSources += sourcesCreated; totalErrors += errors;
  }

  console.log(`\n=== TOTAL: ${totalBrands} brands, ${totalSources} sources, ${totalErrors} errors ===`);
}

main()
  .catch((e) => { console.error('Script error:', e); process.exit(1); })
  .finally(() => prisma.$disconnect());
